import React, { useState, useEffect } from "react";
import "./Main.css";
import Aos from "aos";
import "aos/dist/aos.css";
import { Link } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Loading/Loading.jsx";


function parseNestedJson(jsonString) {
  try {
    const parsedObject = JSON.parse(jsonString);

    // Recursively parse nested JSON strings
    for (const key in parsedObject) {
      if (typeof parsedObject[key] === 'string') {
        try {
          parsedObject[key] = JSON.parse(parsedObject[key]);
        } catch (error) {
          // Handle parsing errors, e.g., log the error or return the original string
          console.error(`Error parsing nested JSON: ${error.message}`);
        }
      }
    }

    return parsedObject;
  } catch (error) {
    console.error(`Error parsing JSON: ${error.message}`);
    return null;
  }
}

function Main({ setIsGlobalLoading }) {
 
  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);


  const [isLoading, setIsLoading] = useState(true);

  const { data, isSuccess, error } = useQuery({
    queryKey: ['todo'],
    queryFn: () => fetch('http://127.0.0.1:8000/api/AllProducts').then((res) => res.json()),
    onSuccess: () => {
      setIsLoading(false);
      setIsGlobalLoading(false); // Set global loading to false when component is loaded
    },
    onError: () => {
      setIsLoading(false);
      setIsGlobalLoading(false); // Set global loading to false on error
    },
  });


return (
  <section className="BG">
  <section id="main" className="main container section">
    <div className="secTitle">
      <h3 data-aos="fade-right" data-aos-duration="1200" className="title">
        Take A Look At Our Products
      </h3>
    </div>
    <div className="secContent grid">
    {isLoading && <Loading />}
    {isSuccess && data.map((product, index) => (
      

        <Link key={index} to={`/Product/${index}`}>
          <div
            data-aos="fade-up"
            data-aos-duration="1200"
            key={index}
            className={"singleProduct"}
          >

            <div className="imageDiv">
              <img
                src={

                  parseNestedJson(product.product_images)['images'][0]} // Access image URL by index
                alt={product.product_images} // Use product name or fallback
              />
            </div>


            <div className="cardInfo">
              <h4 className="productTitle">{product.product_name}</h4>
              <div className="desc">
                <p>{product.product_description}</p>
              </div>
            </div>

          </div>
        </Link>
      
    ))}</div>
    
    {error && <p>Error: {error.message}</p>}
    </section>
  </section>
);
